

# This file was *autogenerated* from the file solver.sage
from sage.all_cmdline import *   # import sage library

_sage_const_7 = Integer(7); _sage_const_8 = Integer(8); _sage_const_1 = Integer(1); _sage_const_256 = Integer(256); _sage_const_25 = Integer(25); _sage_const_0 = Integer(0); _sage_const_3 = Integer(3); _sage_const_5 = Integer(5); _sage_const_4 = Integer(4); _sage_const_21 = Integer(21)
from sage.all import *
import ast
import re

# Fungsi utilitas untuk konversi
def b2l(b):
    return int.from_bytes(b, "big")

def l2b(x):
    x = int(x)
    return x.to_bytes((x.bit_length() + _sage_const_7 ) // _sage_const_8 , "big")

# 1. Parsing data dari output.txt
data = open("output.txt", "r").read()

n = Integer(re.search(r"n = (\d+)", data).group(_sage_const_1 ))
e = Integer(re.search(r"e = (\d+)", data).group(_sage_const_1 ))
ciphertexts = ast.literal_eval(
    re.search(r"ciphertexts = (\[.*\])", data, re.S).group(_sage_const_1 )
)
ciphertexts = [Integer(c) for c in ciphertexts]

# 2. Persiapan Konstanta dan Ring Polinomial
B = Integer(_sage_const_256 ) ** _sage_const_25 
Zn = Zmod(n)
R = PolynomialRing(Zn, names=('x',)); (x,) = R._first_ngens(1)# Ring untuk target utama (F atau Z)
T = PolynomialRing(R, names=('t',)); (t,) = T._first_ngens(1)# Ring sementara untuk mengeliminasi m0 / m4

def relation_poly(ca, cb, a, b):
    """
    Menghasilkan polinomial resultant untuk relasi:
        t^e = ca
        (a*t + b*x)^e = cb
    Dimana 'x' adalah variabel target yang ingin kita isolasi.
    """
    a, b = R(Zn(a)), R(Zn(b))
    ca, cb = R(Zn(ca)), R(Zn(cb))

    f = t**e - ca
    g = (a*t + b*x)**e - cb

    return f.resultant(g).monic()

# 3. Bentuk Polinomial Pertama dari Batch 1 (Relasi c0 & c3)
# m3 = B*m0 + (1 - B^5)*F
P1 = relation_poly(
    ciphertexts[_sage_const_0 ],
    ciphertexts[_sage_const_3 ],
    B,
    _sage_const_1  - B**_sage_const_5 
)

# 4. Bentuk Polinomial Kedua dari Batch 2 (Relasi c4 & c7)
# m7 = 256*B*m4 + (1 - 256*B^5)*Z
# Faktor 256 ditambahkan karena Z lebih panjang 1 byte.
Pz = relation_poly(
    ciphertexts[_sage_const_4 ],
    ciphertexts[_sage_const_7 ],
    _sage_const_256  * B,
    _sage_const_1  - _sage_const_256  * B**_sage_const_5 
)

# Substitusi Z menjadi F: Z = F + delta
delta = (b2l(b"SLOP{") - b2l(b"CBC{")) * (Integer(_sage_const_256 ) ** _sage_const_21 )
P2 = Pz(x + R(Zn(delta))).monic()

# 5. Cari akar bersamanya (F) menggunakan GCD
# --- Tambahkan fungsi GCD manual ---
def poly_gcd(a, b):
    # Pastikan derajat a lebih besar dari b sebelum mulai
    if a.degree() < b.degree():
        a, b = b, a
        
    while b != _sage_const_0 :
        # Paksa b menjadi monic agar pembagian modulo n selalu valid
        b = b.monic()
        a, b = b, a % b
        
    return a.monic()

# 5. Cari akar bersamanya (F) menggunakan fungsi GCD manual
G = poly_gcd(P1, P2)

print("[+] Derajat GCD:", G.degree())
print("[+] Bentuk GCD:", G)

# Pastikan kita mendapat polinomial linear
assert G.degree() == _sage_const_1 

# Jika GCD berbentuk a*x + b, maka akarnya adalah -b/a mod n
a = ZZ(G[_sage_const_1 ])
b = ZZ(G[_sage_const_0 ])

F = (-b * inverse_mod(a, n)) % n
flag = l2b(F)

print("[+] Flag berhasil ditemukan:")
print("    " + flag.decode())

